#!/bin/bash
#SBATCH --job-name=omnifed
#SBATCH --nodes=2
#SBATCH --ntasks-per-node=1
#SBATCH --cpus-per-task=8
#SBATCH --gpus-per-node=1
#SBATCH --time=02:00:00
#SBATCH --signal=B:USR1@180
#SBATCH --ntasks=2
#SBATCH --partition=debug
#SBATCH -o /home/sabiha/OmniFed/outputs/2026-02-17/test_fedavg_centralized_torchdist/slurm-%j.out
#SBATCH -e /home/sabiha/OmniFed/outputs/2026-02-17/test_fedavg_centralized_torchdist/slurm-%j.err
#SBATCH --chdir=/home/sabiha/OmniFed
#SBATCH --gres=gpu:1
#SBATCH --gpus-per-task=1
set -euo pipefail
export PYTHONPATH="${PYTHONPATH:-}:/home/sabiha/OmniFed"
export PYTHONUNBUFFERED=1
export HYDRA_FULL_ERROR=1
export OMNIFED_DEBUG=${OMNIFED_DEBUG:-0}

echo "SLURM_NODELIST=$SLURM_NODELIST on $(hostname)"
echo "Using PYEXE=/home/sabiha/miniconda3/envs/omnifed/bin/python"

srun --ntasks-per-node=1 bash -lc 'mkdir -p /home/sabiha/OmniFed/outputs'
export OMNIFED_CFG_B64=""
srun --ntasks-per-node=1 bash -lc 'echo "$OMNIFED_CFG_B64" | base64 -d > /home/sabiha/OmniFed/outputs/engine_frozen.json'
srun --ntasks-per-node=1 bash -lc 'echo "[$(hostname)] wrote /home/sabiha/OmniFed/outputs/engine_frozen.json; size=$(stat -c%s /home/sabiha/OmniFed/outputs/engine_frozen.json) bytes"'

set -x
srun --export=ALL /home/sabiha/miniconda3/envs/omnifed/bin/python -u -m src.omnifed.slurm_worker --cfg-json /home/sabiha/OmniFed/outputs/engine_frozen.json
set +x
